import { computeRoundProduction, SKILL_TREE_CONFIG, type SkillTreeId } from '../data/skillTree';
import { useDataStore } from '../store';

function appendSystemLog(message: string) {
  const store = useDataStore();
  store.data.系统日志 = `${store.data.系统日志}\n${message}；`;
}

export function useSkillUnlock() {
  const store = useDataStore();

  function canPurchase(id: SkillTreeId): boolean {
    const config = SKILL_TREE_CONFIG[id];
    const entry = store.data.技能树[id];

    if (config.解锁方式 !== 'purchase' || entry.状态) {
      return false;
    }

    return store.data.资源.金钱 >= (config.消耗 ?? 0);
  }

  function purchase(id: SkillTreeId): boolean {
    const config = SKILL_TREE_CONFIG[id];
    const entry = store.data.技能树[id];

    if (config.解锁方式 !== 'purchase') {
      toastr.info(config.解锁说明);
      return false;
    }

    if (entry.状态) {
      toastr.info(`${config.名称} 已解锁`);
      return false;
    }

    const cost = config.消耗 ?? 0;
    if (store.data.资源.金钱 < cost) {
      toastr.warning('金钱不足，无法解锁');
      return false;
    }

    store.data.资源.金钱 -= cost;
    entry.状态 = true;
    store.data.资源.单轮产出 = computeRoundProduction(store.data.技能树);
    appendSystemLog(`解锁${config.名称}`);
    toastr.success(`已解锁 ${config.名称}`);
    return true;
  }

  return {
    canPurchase,
    purchase,
  };
}
