export const Schema = z.object({
    资源: z
        .object({
        单轮产出: z.coerce.number().prefault(0),
        金钱: z.coerce
            .number()
            .transform(value => Math.max(0, value))
            .prefault(0),
    })
        .prefault({}),
    技能树: z
        .object({
        山女: z
            .object({
            状态: z.boolean().prefault(false),
            作用: z.string().prefault('单轮产出+1'),
        })
            .prefault({}),
        温迪戈: z
            .object({
            状态: z.boolean().prefault(false),
            作用: z.string().prefault('单轮产出+5'),
        })
            .prefault({}),
        产房: z
            .object({
            状态: z.boolean().prefault(false),
            作用: z.string().prefault('给鹿生产'),
        })
            .prefault({}),
        巨鹿: z
            .object({
            状态: z.boolean().prefault(false),
            作用: z.string().prefault('让你的鹿变大，单轮产出+10'),
        })
            .prefault({}),
        金鹿: z
            .object({
            状态: z.boolean().prefault(false),
            作用: z.string().prefault('让你的鹿开始发光，单轮产出+10'),
        })
            .prefault({}),
        旋鹿: z
            .object({
            状态: z.boolean().prefault(false),
            作用: z.string().prefault('让你的鹿开始旋转，单轮产出+10'),
        })
            .prefault({}),
        灵鹿: z
            .object({
            状态: z.boolean().prefault(false),
            作用: z.string().prefault('让你的鹿更贴近自然，单轮产出+10'),
        })
            .prefault({}),
        幽鹿: z
            .object({
            状态: z.boolean().prefault(false),
            作用: z.string().prefault('让你的鹿变得透明，单轮产出+10'),
        })
            .prefault({}),
    })
        .prefault({}),
    系统日志: z.string().prefault(''),
    成就: z
        .object({
        居然不是山女: z.boolean().prefault(false),
        第一个温迪戈: z.boolean().prefault(false),
    })
        .prefault({}),
});
