export type BounceEmojiStyleId = 'plain' | 'large' | 'golden' | 'spinning' | 'pulsing' | 'swift' | 'ethereal';

export interface BounceEmojiStyle {
  id: BounceEmojiStyleId;
  名称: string;
  说明: string;
  scale: number;
  speed: number;
  alpha: number;
  /** 每秒旋转弧度，0 表示不旋转 */
  rotation_speed: number;
  /** 缩放呼吸幅度，0 表示不呼吸 */
  pulse_amplitude: number;
  /** 每秒呼吸频率 */
  pulse_speed: number;
  drop_shadow?: {
    color: string;
    alpha: number;
    blur: number;
    distance: number;
    angle: number;
  };
}

