export const BOUNCE_EMOJI_STYLE_ORDER: BounceEmojiStyleId[] = [
  'plain',
  'large',
  'golden',
  'spinning',
  'pulsing',
  'swift',
  'ethereal',
];

export function resolveBounceEmojiStyle(style_id?: string): BounceEmojiStyle {
  if (style_id && style_id in BOUNCE_EMOJI_STYLES) {
    return BOUNCE_EMOJI_STYLES[style_id as BounceEmojiStyleId];
  }
  return BOUNCE_EMOJI_STYLES.plain;
}
