import type { BounceEmojiStyleId } from './bounceEmojiStyles';
import type { Schema } from '../schema';

export type SkillTreeId = keyof Schema['技能树'];

export interface SkillTreeConfig {
  名称: string;
  产出加成: number;
  解锁方式: 'story' | 'purchase';
  解锁说明: string;
  剧情事件?: string;
  消耗?: number;
}

export interface BounceEmojiTarget {
  emoji: string;
  style_id: BounceEmojiStyleId;
}

/** 鹿外观升级技能，优先级从高到低，只应用第一个已解锁的样式 */
