export const SKILL_TREE_ORDER: SkillTreeId[] = [
  '山女',
  '温迪戈',
  '产房',
  '巨鹿',
  '金鹿',
  '旋鹿',
  '灵鹿',
  '幽鹿',
];

export function computeRoundProduction(skill_tree: Schema['技能树']): number {
  return SKILL_TREE_ORDER.reduce((total, id) => {
    if (skill_tree[id].状态) {
      return total + SKILL_TREE_CONFIG[id].产出加成;
    }
    return total;
  }, 0);
}

function resolveDeerStyle(skill_tree: Schema['技能树']): BounceEmojiStyleId {
  for (const entry of DEER_STYLE_PRIORITY) {
    if (skill_tree[entry.id].状态) {
      return entry.style_id;
    }
  }
  return 'plain';
}

export function getBounceEmojiTargets(skill_tree: Schema['技能树']): BounceEmojiTarget[] {
  if (!skill_tree.产房.状态) {
    return [];
  }

  return [
    {
      emoji: '🦌',
      style_id: resolveDeerStyle(skill_tree),
    },
  ];
}
